export const SPHERE_VERTICES = (() => {
    const latBands = 12;
    const longBands = 12;
    const vertices = [];
    for (let lat = 0; lat < latBands; lat++) {
        const theta1 = (lat / latBands) * Math.PI;
        const theta2 = ((lat + 1) / latBands) * Math.PI;
        for (let lon = 0; lon < longBands; lon++) {
            const phi1 = (lon / longBands) * 2 * Math.PI;
            const phi2 = ((lon + 1) / longBands) * 2 * Math.PI;
            // Vertices of the quad
            const p1 = [Math.sin(theta1) * Math.cos(phi1), Math.cos(theta1), Math.sin(theta1) * Math.sin(phi1)];
            const p2 = [Math.sin(theta1) * Math.cos(phi2), Math.cos(theta1), Math.sin(theta1) * Math.sin(phi2)];
            const p3 = [Math.sin(theta2) * Math.cos(phi1), Math.cos(theta2), Math.sin(theta2) * Math.sin(phi1)];
            const p4 = [Math.sin(theta2) * Math.cos(phi2), Math.cos(theta2), Math.sin(theta2) * Math.sin(phi2)];
            // Tri 1
            vertices.push(...p1, ...p1); // Pos + Normal
            vertices.push(...p3, ...p3);
            vertices.push(...p2, ...p2);
            // Tri 2
            vertices.push(...p2, ...p2);
            vertices.push(...p3, ...p3);
            vertices.push(...p4, ...p4);
        }
    }
    return new Float32Array(vertices);
})();
